class Solution {
public:
    bool equalFrequency(string word) {
        unordered_map<char, int> freq;
        for (char c : word) {
            freq[c]++;
        }

        for (int i = 0; i < word.size(); i++) {
            freq[word[i]]--;
            if (freq[word[i]] == 0) {
                freq.erase(word[i]);
            }

            int target = -1;
            bool uniform = true;
            for (auto& pair : freq) {
                if (target == -1) {
                    target = pair.second;
                } else if (pair.second != target) {
                    uniform = false;
                    break;
                }
            }

            if (uniform) {
                return true;
            }

            freq[word[i]]++;
            if (freq[word[i]] == 1) {
                freq.erase(word[i]);
            }
        }

        return false;
    }
};
